/* ---------------------------------- */
/* --- TRAIT VALUE FUNCTION --- */
/* ---------------------------------- */

<<set setup.getTraitValue = function(type, name, size) {
    // Were-Creature - DON'T CHANGE
    if (name === "Were-Creature") {
        return 480;
    }

    // Soul trait - worth 0 value, cannot be traded
    if (name === "Soul") {
        return 0;
    }

    // Fishing milestone traits
    if (name === "Fishing") {
        return 50;
    }
    if (name === "Advanced Angler") {
        return 75;
    }
    if (name === "Master Angler") {
        return 100;
    }
    if (name === "Fishimon Master") {
        return 200;
    }

    // Special handling for jobs - value = total stat requirements
    if (type === "job") {
        if (name === "Unemployed") {
            return -5;
        }

        if (name === "Criminal") {
            return -150;
        }

        var jobReqs = setup.jobRequirements[name];
        if (jobReqs) {
            var totalReqs = 0;
            for (var stat in jobReqs) {
                totalReqs += jobReqs[stat];
            }
            return totalReqs;
        }
        return 15; // Default job value
    }

    // Body parts - DON'T CHANGE
    if (type === "bodyPart") {
        if (name === "chest" || name === "butt") {
            var sizeValues = {
                "flat masculine": 10,
                "flat": 10,
                "small": 20,
                "medium": 50,
                "large": 70,
                "huge": 100,
                "giant": 150,
                "gigantic": 300   // NEW SIZE VALUE
            };
            return sizeValues[size.toLowerCase()] || 12;
        }
        // Genital values
        if (name === "genitals") {
            var genitalValues = {
                "small penis": 15,
                "penis": 25,
                "big penis": 40,
                "tight vagina": 15,
                "vagina": 25,
                "loose vagina": 40
            };

