<<set setup.getNPCsByJob = function(jobName) {
    var npcs = State.variables.npcs;
    var result = [];

    for (var i = 0; i < npcs.length; i++) {
        var npc = npcs[i];

        // Handle unemployed specifically - NPCs with no jobs array or empty jobs array
        if (jobName === "Unemployed") {
            if (!npc.jobs || npc.jobs.length === 0) {
                result.push(npc);
            }
        } else {
            // Regular job matching - only include if they have this specific job
            if (npc.jobs && npc.jobs.length > 0 && npc.jobs.includes(jobName)) {
                result.push(npc);
            }
        }
    }

    return result;
}>>

