<<set setup.getRelationshipTradeBonus = function(npcName) {
    var v = State.variables;
    if (!v.relationships[npcName]) return 0;

    var level = v.relationships[npcName].level;
    // Level 1 (Stranger) = 0%, each level after gives +3%
    if (level <= 1) return 0;
    return (level - 1) * 3;
