<<set setup.calculateTradeValue = function(tradePackage, isPlayer) {
    var totalValue = 0;

    // Add physical traits
    if (tradePackage.physical && tradePackage.physical.length > 0) {
        for (var i = 0; i < tradePackage.physical.length; i++) {
            totalValue += setup.getTraitValue("physical", tradePackage.physical[i]);
        }
    }

    // Add mental traits
    if (tradePackage.mental && tradePackage.mental.length > 0) {
        for (var i = 0; i < tradePackage.mental.length; i++) {
            totalValue += setup.getTraitValue("mental", tradePackage.mental[i]);
        }
    }

    // Add skills
